def load_coder_file(path, coder_name, sheet_name=0):
    """Load one coder's Excel file. Handles column typo + label normalisation."""
    df = pd.read_excel(path, sheet_name=sheet_name)
    df.columns = [c.strip().lower() for c in df.columns]
    df = df.rename(columns=COLUMN_RENAMES)
    needed = {"tense", "text", "purpose", "certainty"}
    missing = needed - set(df.columns)
    if missing:
        raise KeyError(f"{path}: missing {missing}. Found: {list(df.columns)}")
    for col in ("tense", "purpose", "certainty"):
        df[col] = (df[col].astype(str).str.strip().str.lower()
                   .replace({"nan": np.nan, "": np.nan, "none": np.nan}))
    for col, mapping in VALUE_NORMALISATION.items():
        if mapping:
            df[col] = df[col].replace(mapping)
    df["coder"] = coder_name
    df["text"] = df["text"].astype(str).str.strip()
    return df[["coder", "tense", "text", "purpose", "certainty"]]


def build_wide_frame(frames, reference_coder, corrupted_rows=None):
    """Align coder files by sentence text, patch known corruptions."""
    frames = {k: v.copy() for k, v in frames.items()}
    if corrupted_rows:
        for coder, patches in corrupted_rows.items():
            for idx, correct_text in patches.items():
                frames[coder].loc[idx, "text"] = correct_text
    ref = frames[reference_coder][["text", "tense"]].reset_index(drop=True)
    ref["sentence_id"] = np.arange(1, len(ref) + 1)
    wide = ref.copy()
    for coder, df in frames.items():
        if df["text"].duplicated().any():
            raise ValueError(f"Coder {coder} has duplicate texts — cannot align.")
        sub = df[["text", "purpose", "certainty"]].rename(
            columns={"purpose": f"{coder}_purpose", "certainty": f"{coder}_certainty"}
        )
        wide = wide.merge(sub, on="text", how="left")
    return wide


def load_final_gold(adjudication_path, coder_files, reference_coder="AD"):
    """Reconstruct the final 300-row gold DataFrame."""
    frames = {name: load_coder_file(p, name) for name, p in coder_files.items()}
    # Patch JC row 234 if present (known corruption from v1/v2)
    ad_text = frames["AD"]["text"].iloc[234]
    corrupted = {"JC": {234: ad_text}} if "JC" in frames else None
    wide = build_wide_frame(frames, reference_coder=reference_coder,
                            corrupted_rows=corrupted)
    coders = list(frames.keys())

    adj = pd.read_excel(adjudication_path, sheet_name="adjudicate")
    adj.columns = [c.strip() for c in adj.columns]

    gold = wide[["sentence_id", "tense", "text"]].copy()
    for dim in ("purpose", "certainty"):
        # Unanimous fallback for rows not in adjudication
        unan = []
        for _, row in wide.iterrows():
            labels = [row[f"{c}_{dim}"] for c in coders]
            labels_nn = [l for l in labels if pd.notna(l)]
            if labels_nn and len(set(labels_nn)) == 1:
                unan.append(labels_nn[0])
            else:
                unan.append(np.nan)
        unanimous = pd.Series(unan, index=wide.index)
        # Adjudicated labels
        adj_map = adj.set_index("sentence_id")[f"adjudication_{dim}"].to_dict()
        adjudicated = gold["sentence_id"].map(adj_map)
        adjudicated = (adjudicated.astype(str).str.strip().str.lower()
                       .replace({"": np.nan, "nan": np.nan, "none": np.nan}))
        gold[dim] = adjudicated.fillna(unanimous)

    missing = gold[["purpose", "certainty"]].isna().any(axis=1).sum()
    if missing:
        print(f"[warn] Dropping {missing} sentences with missing labels")
        gold = gold.dropna(subset=["purpose", "certainty"]).reset_index(drop=True)

    gold["tense"] = gold["tense"].str.strip().str.lower()
    gold["text"] = gold["text"].str.strip()
    return gold[["sentence_id", "tense", "text", "purpose", "certainty"]]

