# Load splits from saved JSON instead of rebuilding them
from dataclasses import dataclass

@dataclass
class NestedSplits:
    dimension: str
    test_ids: list
    cv_folds: list
    seed: int

    @classmethod
    def from_json(cls, path):
        p = json.loads(Path(path).read_text())
        return cls(
            dimension=p["dimension"],
            test_ids=p["test_ids"],
            cv_folds=[(f["train_ids"], f["val_ids"]) for f in p["cv_folds"]],
            seed=p["seed"],
        )

splits = {
    dim: NestedSplits.from_json(Path(CONFIG["output_dir"]) / f"splits_{dim}.json")
    for dim in CONFIG["dimensions"]
}

for dim, s in splits.items():
    print(f"  {dim}: test={len(s.test_ids)}, cv_folds={len(s.cv_folds)}")

